import { useEditionStore } from "@/stores/EditionStore";

export const zoomMore = () => {
  const editionStore = useEditionStore();
  editionStore.zoomMultiplier = parseFloat(
    (editionStore.zoomMultiplier + 0.1).toFixed(2)
  );
};

export const zoomLess = () => {
  const editionStore = useEditionStore();
  editionStore.zoomMultiplier = parseFloat(
    (editionStore.zoomMultiplier - 0.1).toFixed(2)
  );
};
